// core/tree/engine/TreeFiltering.ts

import type { TreeNode } from '../models/TreeNode';

/**
 * Filters tree nodes based on query and mode.
 */
export function filterTree(
  nodes: TreeNode[] | undefined,
  query: string,
  options?: {
    filterBy?: string;
    filterMode?: 'lenient' | 'strict';
  }
): TreeNode[] {
  if (!nodes || !query) {
    return nodes || [];
  }

  const filterBy = options?.filterBy?.split(',') || ['label'];
  const filterMode = options?.filterMode || 'lenient';
  const lowerQuery = query.toLowerCase();

  function matches(node: TreeNode): boolean {
    return filterBy.some((field) => {
      const value = resolveField(node, field);
      return (
        typeof value === 'string' &&
        value.toLowerCase().includes(lowerQuery)
      );
    });
  }

  function filterNode(node: TreeNode): TreeNode | null {
    const nodeMatches = matches(node);

    if (nodeMatches && filterMode === 'lenient') {
      // include node with all descendants untouched
      return { ...node };
    }

    if (!node.children || node.children.length === 0) {
      return nodeMatches ? { ...node } : null;
    }

    const filteredChildren = node.children
      .map(filterNode)
      .filter(Boolean) as TreeNode[];

    if (nodeMatches || filteredChildren.length > 0) {
      return {
        ...node,
        children: filteredChildren,
      };
    }

    return null;
  }

  return nodes
    .map(filterNode)
    .filter(Boolean) as TreeNode[];
}

/**
 * Resolves nested field paths like "data.name".
 */
function resolveField(node: TreeNode, path: string): any {
  const parts = path.split('.');
  let value: any = node;

  for (const part of parts) {
    if (value == null) return null;
    value = value[part];
  }

  return value;
}
